// 将所有一级标题（章标题）设置为黑体三号加粗居中，段前12磅段后6磅无缩进
var doc = Application.ActiveDocument;
var range = doc.Range();
range.Find.ClearFormatting();
range.Find.Font.Name = "黑体";
range.Find.Font.Size = 16;
range.Find.Font.Bold = true;
range.Find.ParagraphFormat.Alignment = 1; // 居中
range.Find.ParagraphFormat.SpaceBefore = 12 * 72 / 72; // 12磅
range.Find.ParagraphFormat.SpaceAfter = 6 * 72 / 72; // 6磅
range.Find.ParagraphFormat.FirstLineIndent = 0;
range.Find.Execute("第[0-9]+章", false);
